import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const LoginPage = () => {
  const [isLogin, setIsLogin] = useState(true);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = (e) => {
    e.preventDefault();
    setLoading(true);
    setTimeout(() => {
      navigate('/dashboard'); // Direct entry to the SOC
    }, 1500);
  };

  return (
    <div style={styles.container}>
      {/* Dynamic Circuit Background */}
      <div style={styles.bgCircuit}></div>
      
      <div style={styles.card}>
        <div style={styles.header}>
          <h1 style={styles.title}>{isLogin ? 'Welcome Back' : 'Create Node'}</h1>
          <p style={styles.subtitle}>{isLogin ? 'Please login to your account' : 'Register new analyst identifier'}</p>
        </div>

        <form onSubmit={handleSubmit} style={styles.form}>
          <div style={styles.inputGroup}>
            <label style={styles.label}>Email / ID</label>
            <input type="email" placeholder="Enter your email" style={styles.input} required />
          </div>

          <div style={styles.inputGroup}>
            <label style={styles.label}>Password</label>
            <input type="password" placeholder="Enter your password" style={styles.input} required />
          </div>

          {isLogin && (
            <div style={styles.options}>
              <label style={styles.remember}><input type="checkbox" /> Remember me</label>
              <span style={styles.forgot}>Forgot Password?</span>
            </div>
          )}

          <button type="submit" style={styles.mainBtn}>
            {loading ? 'Initializing...' : (isLogin ? 'Login' : 'Sign Up')}
          </button>
        </form>

        <div style={styles.divider}>or</div>

        <div style={styles.socialGroup}>
          <button style={styles.socialBtn}>
            <img src="https://img.icons8.com/color/24/000000/google-logo.png" alt="G" /> Login With Google
          </button>
          <button style={styles.socialBtn}>
            <img src="https://img.icons8.com/ios-filled/24/ffffff/github.png" alt="H" /> Login With GitHub
          </button>
        </div>

        <div style={styles.footer}>
          {isLogin ? "Don't have an Account?" : "Already have an identifier?"} 
          <span style={styles.toggle} onClick={() => setIsLogin(!isLogin)}>
            {isLogin ? ' Sign Up' : ' Login'}
          </span>
        </div>
      </div>
    </div>
  );
};

const styles = {
  container: {
    backgroundColor: '#0f1219',
    height: '100vh',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    fontFamily: "'Inter', sans-serif",
    position: 'relative',
    overflow: 'hidden'
  },
  bgCircuit: {
    position: 'absolute',
    width: '100%',
    height: '100%',
    backgroundImage: 'url("https://www.transparenttextures.com/patterns/circuit-board.png")',
    opacity: 0.1,
    zIndex: 0
  },
  card: {
    width: '420px',
    backgroundColor: '#1c212c',
    borderRadius: '20px',
    padding: '40px',
    boxShadow: '0 20px 50px rgba(0,0,0,0.5)',
    zIndex: 1,
    border: '1px solid #2d3544'
  },
  header: { textAlign: 'center', marginBottom: '30px' },
  title: { color: '#ffffff', fontSize: '28px', margin: '0 0 10px 0' },
  subtitle: { color: '#94a3b8', fontSize: '14px' },
  inputGroup: { marginBottom: '20px' },
  label: { display: 'block', color: '#cbd5e1', fontSize: '12px', marginBottom: '8px', fontWeight: 'bold' },
  input: {
    width: '100%',
    padding: '12px',
    backgroundColor: '#2d3544',
    border: '1px solid #3f4a5d',
    borderRadius: '10px',
    color: 'white',
    outline: 'none',
    boxSizing: 'border-box'
  },
  options: { display: 'flex', justifyContent: 'space-between', fontSize: '12px', color: '#94a3b8', marginBottom: '20px' },
  forgot: { color: '#6366f1', cursor: 'pointer' },
  mainBtn: {
    width: '100%',
    padding: '14px',
    backgroundColor: '#5865f2',
    color: 'white',
    border: 'none',
    borderRadius: '10px',
    fontWeight: 'bold',
    cursor: 'pointer',
    transition: '0.3s'
  },
  divider: { textAlign: 'center', color: '#475569', margin: '20px 0', fontSize: '12px', position: 'relative' },
  socialGroup: { display: 'flex', flexDirection: 'column', gap: '12px' },
  socialBtn: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: '10px',
    width: '100%',
    padding: '12px',
    backgroundColor: 'transparent',
    border: '1px solid #3f4a5d',
    borderRadius: '10px',
    color: 'white',
    cursor: 'pointer',
    fontSize: '14px'
  },
  footer: { textAlign: 'center', marginTop: '25px', color: '#94a3b8', fontSize: '13px' },
  toggle: { color: '#5865f2', fontWeight: 'bold', cursor: 'pointer' }
};

export default LoginPage;
